mapper.update:
UPDATE trace_failure_patterns
SET occurrence_count = occurrence_count + #{increment},
    last_seen_at = #{lastSeenAt},
    sample_trace_ids = #{sampleTraceIds}
WHERE pattern_key = #{patternKey}
